        content = Array.from(paragraphs).map(p => p.textContent.trim()).filter(t => t).join('\n');
      } else {
        content = bodyEl.textContent.trim().substring(0, 500);
      }
    }
    if (!content) content = '（正文提取失败）';
    // 限制正文长度
    if (content.length > 800) content = content.substring(0, 800) + '...';

