const items = window.__store.p6;
const results = [];

for (let i = 0; i < items.length; i++) {
  const item = items[i];
  const url = item.attrs.href;
  const listTitle = item.text;

  try {
    const resp = await fetch(url, {
      headers: { 'User-Agent': 'Mozilla/5.0' }
    });
    const html = await resp.text();
    const doc = new DOMParser().parseFromString(html, 'text/html');

    // 提取标题
    let title = '';
    const titleEl = doc.querySelector('h1.main-title') || doc.querySelector('#artibodyTitle') || doc.querySelector('.art_title');
    if (titleEl) title = titleEl.textContent.trim();
    if (!title) title = listTitle;

    // 提取正文
    let content = '';
    const bodyEl = doc.querySelector('#artibody') || doc.querySelector('.art_content') || doc.querySelector('article');
    if (bodyEl) {
      // 提取所有段落文本
      const paragraphs = bodyEl.querySelectorAll('p');
      if (paragraphs.length > 0) {
        content = Array.from(paragraphs).map(p => p.textContent.trim()).filter(t => t).join('\n');
      } else {
        content = bodyEl.textContent.trim().substring(0, 500);
      }
    }
    if (!content) content = '（正文提取失败）';
    // 限制正文长度
    if (content.length > 800) content = content.substring(0, 800) + '...';

    // 提取时间
    let date = '';
    const dateEl = doc.querySelector('.time-source') || doc.querySelector('.art_time') || doc.querySelector('.pub_time') || doc.querySelector('time');
    if (dateEl) date = dateEl.textContent.trim();

    // 提取来源
    let source = '';
    const sourceEl = doc.querySelector('.time-source a') || doc.querySelector('.source') || doc.querySelector('.art_source');
    if (sourceEl) source = sourceEl.textContent.trim();

    results.push({
      title,
      url,
      date,
      source,
      content
    });

  } catch (e) {
    results.push({
      title: listTitle,
      url,
      date: '',
      source: '',
      content: '（抓取失败: ' + e.message + '）'
    });
  }
}

return results;
